module SR_Latch (
    input wire S,
    input wire R,
    output reg obf_Q,
    output reg Qn
);
    always @ (S or R) begin
        if (S == 1 && R == 0) begin
            obf_Q <= 1;
            Qn <= 0;
        end else if (S == 0 && R == 1) begin
            obf_Q <= 0;
            Qn <= 1;
        end else if (S == 0 && R == 0) begin
            // Hold state
            // obf_Q and Qn retain their previous values
        end else if (S == 1 && R == 1) begin
            // Invalid state
            obf_Q <= 1'bx;
            Qn <= 1'bx;
        end
    end
endmodule
